      {/* Floating Actions */}
      {imageUrl && !loading && (
        <div className={`absolute bottom-6 right-6 z-20 flex gap-3 transition-opacity duration-300 ${isHovering ? 'opacity-100' : 'opacity-0 md:opacity-100'}`}>
          <button 
            onClick={handleDownload}
