        {activeCategory === 'Vehicle' && (
          <div className="space-y-4 animate-fadeIn">
            <div className="form-group">
              <label className="text-gray-400 text-xs uppercase font-bold mb-2 block">Manufacturer</label>
              <select 
                value={config.make} 
                onChange={(e) => {
